import{_ as a,o as r,c as l,ae as e}from"./chunks/framework.DAK3ioSj.js";const c=JSON.parse('{"title":"SkillX","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillx.md","filePath":"radar/tech-skillx.md"}'),o={name:"radar/tech-skillx.md"};function i(d,t,h,n,s,u){return r(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="skillx" tabindex="-1">SkillX <a class="header-anchor" href="#skillx" aria-label="Permalink to &quot;SkillX&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.41</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 把 Skill 显式分为<strong>策略层 / 功能层 / 原子层三层粒度</strong>，强模型经验向弱模型蒸馏。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2604.04804" target="_blank" rel="noreferrer">arXiv 2604.04804</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="三层-skill-设计" tabindex="-1">三层 Skill 设计 <a class="header-anchor" href="#三层-skill-设计" aria-label="Permalink to &quot;三层 Skill 设计&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层</th><th>含义</th><th>例子</th></tr></thead><tbody><tr><td><strong>策略层</strong></td><td>高层规划</td><td>&quot;先认证再操作&quot;</td></tr><tr><td><strong>功能层</strong></td><td>具体步骤</td><td>&quot;用 OAuth2 获取 Token&quot;</td></tr><tr><td><strong>原子层</strong></td><td>最小操作单元</td><td>&quot;发送 POST 请求&quot;</td></tr></tbody></table><blockquote><p>像乐高积木 —— 底座不同但上面的结构件通用。上层 Skill 跨 Agent 复用，底层 Skill 适配不同环境。</p></blockquote><h3 id="强模型蒸馏给弱模型" tabindex="-1">强模型蒸馏给弱模型 <a class="header-anchor" href="#强模型蒸馏给弱模型" aria-label="Permalink to &quot;强模型蒸馏给弱模型&quot;">​</a></h3><p>GPT-4 级别模型积累的 Skill 经验可被 GPT-3.5 级别模型直接消费。AppWorld / τ²-Bench 上弱模型获得显著提升。</p><h3 id="解决-团队各自重复发明轮子" tabindex="-1">解决&quot;团队各自重复发明轮子&quot; <a class="header-anchor" href="#解决-团队各自重复发明轮子" aria-label="Permalink to &quot;解决&quot;团队各自重复发明轮子&quot;&quot;">​</a></h3><p>公司 10 个团队各自教 Agent 调用内部 API → SkillX 让一个团队的经验沉淀成可复用三层 Skill 给其他团队用。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>三层 Skill 粒度自动划分</li><li>跨模型蒸馏</li><li>跨团队 Skill 复用</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>跨环境迁移需要<strong>底层工具集相对稳定</strong> —— 如果两个环境的 API 完全不同，上层 Skill 也难复用</li><li><strong>没有自动化工具帮使用者判断&quot;当前 Skill 是太抽象了还是太具体了&quot;</strong> —— 三层粒度是设计准则而非自动决策</li><li>学术阶段，未产品化</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.45</td><td>论文阶段</td></tr><tr><td>创新性</td><td>0.65</td><td>三层粒度设计有启发性</td></tr><tr><td>落地程度</td><td>0.25</td><td>未开源</td></tr><tr><td>生态活跃度</td><td>0.25</td><td>较少</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.41</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2604.04804" target="_blank" rel="noreferrer">SkillX 论文</a></li></ul>',31)])])}const b=a(o,[["render",i]]);export{c as __pageData,b as default};
